  ('locality-8b44517b-moex-00138', 'locality-8b44517b', 'locality-8b44517b-moex-112-3082b5f1', 'sub-locality-8b44517b-04', NULL, 'single_choice', '下列何者得以法規命令規範之？', '["對於因全民健康保險所生之權利義務", "課予納稅之義務", "時效制度", "特別公課徵收之要件及程序"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:31+00:00", "source_pdf_sha1": "1c9608aa1601", "answer_pdf_sha1": "e6715e904b3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "307", "s": "0708", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('locality-8b44517b-moex-00139', 'locality-8b44517b', 'locality-8b44517b-moex-112-3082b5f1', 'sub-locality-8b44517b-04', NULL, 'single_choice', '人民甲欲申請建築許可，經乙機關審查通過並發給執照。在該建築許可的法定救濟期間經過後， 乙機關才發現該建築許可之作成具有瑕疵，欲加以撤銷。下列敘述何者正確？', '["基於依法行政原則，該違法之建築許可不得作為甲的信賴基礎", "即使當初是因為甲提供錯誤之資料，致使乙作成該建築許可時，甲仍然可主張信賴保護", "縱使甲之信賴值得保護，但經權衡信賴利益與公益之後，乙仍然可以撤銷該建築許可，只是應 給予補償", "若該建築許可經乙撤銷後，原則上自撤銷之日起失其效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:31+00:00", "source_pdf_sha1": "1c9608aa1601", "answer_pdf_sha1": "e6715e904b3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "307", "s": "0708", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('locality-8b44517b-moex-00140', 'locality-8b44517b', 'locality-8b44517b-moex-112-3082b5f1', 'sub-locality-8b44517b-04', NULL, 'single_choice', '下列何者非屬行政處分？', '["經濟部標準檢驗局於申請後，認定受檢驗商品為合格", "人民未經申請集會而集會，警察舉牌命令立即解散集會遊行", "衛生主管機關在官方網站上公告傳染病大流行，促請民眾於公眾聚集場所配戴口罩", "主管機關對於未履行拆除義務之違建行為人發出通知，告戒7日後將逕行拆除"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:31+00:00", "source_pdf_sha1": "1c9608aa1601", "answer_pdf_sha1": "e6715e904b3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "307", "s": "0708", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('locality-8b44517b-moex-00141', 'locality-8b44517b', 'locality-8b44517b-moex-112-3082b5f1', 'sub-locality-8b44517b-04', NULL, 'single_choice', '甲因欠稅超過新臺幣1,000萬元，財政部因而依稅捐稽徵法第24條第3項規定函請內政部移民署 限制甲出境，嗣經該署向甲核發限制出境之處分。下列敘述何者正確？', '["該限制出境處分係屬根據機關間權限委託所作成之行政處分", "該限制出境處分係屬多階段之行政處分", "該限制出境處分係屬根據機關間權限委任所作成之行政處分", "該限制出境處分係屬對人之一般處分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:31+00:00", "source_pdf_sha1": "1c9608aa1601", "answer_pdf_sha1": "e6715e904b3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "307", "s": "0708", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "勞工行政"}'::jsonb, NULL)
